class Solution {
public:
    string sortString(string s) {
        string result;
        while (!s.empty()) {
            for (char c = 'a'; c <= 'z'; ++c) {
                auto it = s.find(c);
                if (it != string::npos) {
                    result += c;
                    s.erase(it, 1);
                    break;
                }
            }
            for (char c = 'z'; c >= 'a'; --c) {
                auto it = s.find(c);
                if (it != string::npos) {
                    result += c;
                    s.erase(it, 1);
                    break;
                }
            }
        }
        return result;
    }
};
